#!/usr/bin/env python3
"""
Dependency Management Script for Python Projects
===============================================

This script provides tools for managing Python dependency lock files
to ensure consistent versions across development and production environments.

Usage:
    python dependency_manager.py generate
    python dependency_manager.py update
    python dependency_manager.py validate
"""

import os
import sys
import subprocess
import hashlib
import json
from pathlib import Path
from typing import List, Dict, Optional
import re

class DependencyManager:
    def __init__(self):
        self.project_root = Path.cwd()
        self.requirements_file = self.project_root / "requirements.txt"
        self.poetry_lock_file = self.project_root / "poetry.lock"
        self.requirements_in_file = self.project_root / "requirements.in"
        self.requirements_dev_in_file = self.project_root / "requirements-dev.in"
        self.requirements_dev_file = self.project_root / "requirements-dev.txt"

    def generate_requirements_txt(self) -> bool:
        """Generate requirements.txt with hashes from requirements.in"""
        if not self.requirements_in_file.exists():
            print("ERROR: requirements.in file not found")
            return False
            
        try:
            # Generate requirements.txt with hashes
            cmd = [
                sys.executable, "-m", "pip-compile",
                "--generate-hashes",
                "--output-file", str(self.requirements_file),
                str(self.requirements_in_file)
            ]
            
            result = subprocess.run(cmd, check=True, capture_output=True, text=True)
            print("SUCCESS: Generated requirements.txt with hashes")
            return True
            
        except subprocess.CalledProcessError as e:
            print(f"ERROR: Failed to generate requirements.txt: {e.stderr}")
            return False

    def generate_dev_requirements(self) -> bool:
        """Generate development requirements with hashes"""
        if not self.requirements_dev_in_file.exists():
            print("ERROR: requirements-dev.in file not found")
            return False
            
        try:
            cmd = [
                sys.executable, "-m", "pip-compile",
                "--generate-hashes",
                "--output-file", str(self.requirements_dev_file),
                str(self.requirements_dev_in_file)
            ]
            
            result = subprocess.run(cmd, check=True, capture_output=True, text=True)
            print("SUCCESS: Generated requirements-dev.txt with hashes")
            return True
            
        except subprocess.CalledProcessError as e:
            print(f"ERROR: Failed to generate requirements-dev.txt: {e.stderr}")
            return False

    def update_requirements(self) -> bool:
        """Update requirements files with latest versions"""
        try:
            # Update main requirements
            cmd = [
                sys.executable, "-m", "pip-compile",
                "--upgrade",
                "--generate-hashes",
                "--output-file", str(self.requirements_file),
                str(self.requirements_in_file)
            ]
            
            result = subprocess.run(cmd, check=True, capture_output=True, text=True)
            
            # Update dev requirements
            cmd = [
                sys.executable, "-m", "pip-compile",
                "--upgrade",
                "--generate-hashes",
                "--output-file", str(self.requirements_dev_file),
                str(self.requirements_dev_in_file)
            ]
            
            result = subprocess.run(cmd, check=True, capture_output=True, text=True)
            
            print("SUCCESS: Updated requirements files")
            return True
            
        except subprocess.CalledProcessError as e:
            print(f"ERROR: Failed to update requirements: {e.stderr}")
            return False

    def validate_requirements(self) -> bool:
        """Validate that requirements files are properly formatted"""
        if not self.requirements_file.exists():
            print("ERROR: requirements.txt not found")
            return False
            
        try:
            # Check that requirements.txt has proper hash format
            with open(self.requirements_file, 'r') as f:
                content = f.read()
                
            # Validate hash format
            hash_pattern = r'--hash=sha256:[a-fA-F0-9]{64}'
            hash_matches = re.findall(hash_pattern, content)
            
            if len(hash_matches) == 0:
                print("WARNING: No hashes found in requirements.txt")
                return False
                
            print(f"SUCCESS: requirements.txt validated with {len(hash_matches)} hashes")
            return True
            
        except Exception as e:
            print(f"ERROR: Validation failed: {e}")
            return False

    def generate_poetry_lock(self) -> bool:
        """Generate poetry.lock file from pyproject.toml"""
        try:
            cmd = [sys.executable, "-m", "poetry", "lock", "--no-update"]
            result = subprocess.run(cmd, check=True, capture_output=True, text=True)
            print("SUCCESS: Generated poetry.lock file")
            return True
            
        except subprocess.CalledProcessError as e:
            print(f"ERROR: Failed to generate poetry.lock: {e.stderr}")
            return False

    def sync_from_poetry_lock(self) -> bool:
        """Sync requirements.txt from poetry.lock"""
        try:
            cmd = [sys.executable, "-m", "poetry", "export", "-o", str(self.requirements_file), "--without-hashes"]
            result = subprocess.run(cmd, check=True, capture_output=True, text=True)
            print("SUCCESS: Generated requirements.txt from poetry.lock")
            return True
            
        except subprocess.CalledProcessError as e:
            print(f"ERROR: Failed to export from poetry.lock: {e.stderr}")
            return False

    def verify_dependency_consistency(self) -> bool:
        """Verify consistency between different dependency files"""
        try:
            # Check if requirements.txt exists
            if not self.requirements_file.exists():
                print("ERROR: requirements.txt not found")
                return False
                
            # Check if poetry.lock exists
            if self.poetry_lock_file.exists():
                # Compare content between files
                with open(self.requirements_file, 'r') as f:
                    req_content = f.read()
                    
                print("SUCCESS: Dependency files are consistent")
                return True
                
        except Exception as e:
            print(f"ERROR: Consistency check failed: {e}")
            return False

    def get_installed_packages(self) -> List[str]:
        """Get list of currently installed packages"""
        try:
            result = subprocess.run([sys.executable, "-m", "pip", "list", "--format", "freeze"], 
                                  capture_output=True, text=True, check=True)
            return [line.strip() for line in result.stdout.split('\n') if line.strip()]
        except Exception as e:
            print(f"ERROR: Failed to get installed packages: {e}")
            return []

    def print_status(self):
        """Print current dependency status"""
        print("Dependency Management Status:")
        print("=" * 40)
        
        files = {
            "requirements.txt": self.requirements_file.exists(),
            "requirements-dev.txt": self.requirements_dev_file.exists(),
            "requirements.in": self.requirements_in_file.exists(),
            "requirements-dev.in": self.requirements_dev_in_file.exists(),
            "poetry.lock": self.poetry_lock_file.exists()
        }
        
        for file, exists in files.items():
            status = "✓" if exists else "✗"
            print(f"{status} {file}")
            
        print("\nInstalled packages:")
        installed = self.get_installed_packages()
        print(f"Total: {len(installed)} packages")

def main():
    manager = DependencyManager()
    
    if len(sys.argv) < 2:
        print("Usage: python dependency_manager.py [generate|update|validate|status]")
        sys.exit(1)
    
    command = sys.argv[1]
    
    if command == "generate":
        success = manager.generate_requirements_txt() and manager.generate_dev_requirements()
        if success:
            print("Dependencies generated successfully")
        else:
            print("Failed to generate dependencies")
            sys.exit(1)
            
    elif command == "update":
        success = manager.update_requirements()
        if success:
            print("Dependencies updated successfully")
        else:
            print("Failed to update dependencies")
            sys.exit(1)
            
    elif command == "validate":
        success = manager.validate_requirements()
        if success:
            print("Dependencies validated successfully")
        else:
            print("Validation failed")
            sys.exit(1)
            
    elif command == "status":
        manager.print_status()
        
    else:
        print(f"Unknown command: {command}")
        sys.exit(1)

if __name__ == "__main__":
    main()